/**
 * AttributeContext entity with detection metadata
 *
 * Cross-cutting email attributes with parallel detection capabilities,
 * supporting attribute relevance matrix roles per SCORING_LOGIC.md.
 */

export interface AttributeContext {
  emailId: string;

  // Detected attributes
  urgency: 'low' | 'medium' | 'high';
  domains: string[];
  structuralPatterns: string[];
  temporalSignals: string[];

  // Enhanced attribute detection with parallel processing
  detectionMetadata: Record<string, AttributeDetectionMetadata>;

  // Attribute influence tracking per SCORING_LOGIC.md Attribute Relevance Matrix
  influenceApplications: AttributeInfluenceApplication[];

  // Derived attributes and cross-attribute relationships
  derivedAttributes: Record<string, DerivedAttributeResult>;
  attributeRelationships: AttributeRelationship[];
}

/**
 * Attribute detection metadata with parallel processing support
 */
export interface AttributeDetectionMetadata {
  detectedAt: Date;
  confidence: number;
  detectionMethod:
    | 'rule'
    | 'pattern'
    | 'ai'
    | 'domainLookup'
    | 'derived'
    | 'keywordAnalysis'
    | 'headerAnalysis'
    | 'textAnalysis'
    | 'nlpAnalysis'
    | 'temporalAnalysis'
    | 'sentimentAnalysis';
  parallelProcessed?: boolean;
  dependencies?: string[]; // Other attributes this detection depended on

  // Detection details
  sourceField?: string; // Which email field triggered detection
  matchedValue?: string; // Specific value that matched
  evidence?: string; // Evidence description for test compatibility
  detectorConfig?: AttributeDetectorConfig;

  // Performance tracking
  detectionTimeMs?: number;
  cacheUsed?: boolean;
  retryCount?: number;
}

export interface AttributeDetectorConfig {
  field: string;
  operation: string;
  values: string[];
  weight: number;
  cacheEnabled: boolean;
  parallelSafe: boolean;
}

/**
 * Attribute influence application per SCORING_LOGIC.md Attribute Relevance Matrix
 */
export interface AttributeInfluenceApplication {
  targetCategory: string;
  attributeUsed: string;
  roleType: AttributeRole;
  scoreImpact: number;
  applicationReason: string;

  // Parallel processing context
  appliedDuringParallelExecution: boolean;
  dependentOnAttributes: string[];
  influenceTimestamp: Date;

  // Quality tracking
  influenceReliability: number;
  historicalAccuracy: number;
}

/**
 * Attribute roles from SCORING_LOGIC.md Attribute Relevance Matrix
 */
export type AttributeRole =
  | 'CORE' // Essential for category identification
  | 'PRIMARY_BOOST' // Strong positive indicator
  | 'SECONDARY_BOOST' // Moderate positive indicator
  | 'DISAMBIGUATOR' // Helps resolve ties between categories
  | 'FILTER' // Can exclude categories
  | 'STRUCTURAL' // Indicates email structure/format
  | 'DERIVED_LINK' // Links to derived attributes
  | 'NEUTRAL'; // No significant influence

/**
 * Derived attribute calculation results
 */
export interface DerivedAttributeResult {
  attributeName: string;
  derivationLogic: string;
  sourceAttributes: string[];
  calculatedValue: unknown;
  confidence: number;

  // Parallel processing metadata
  calculatedDuringParallelExecution: boolean;
  calculationTimeMs: number;
  cacheHit: boolean;

  // Quality metrics
  derivationAccuracy: number;
  logicConsistency: number;
}

/**
 * Relationships between attributes for cross-attribute analysis
 */
export interface AttributeRelationship {
  fromAttribute: string;
  toAttribute: string;
  relationshipType: 'implies' | 'excludes' | 'enhances' | 'diminishes' | 'neutral';
  strength: number; // 0.0 to 1.0
  reason: string;

  // Context tracking
  discoveredDuringProcessing: boolean;
  validatedAcrossEmails: number;
  conflictOccurrences: number;
}

/**
 * Extended attribute context with comprehensive detection and analysis
 */
export interface ExtendedAttributeContext extends AttributeContext {
  // Advanced attribute analysis
  attributeCorrelations: AttributeCorrelation[];
  unusualPatterns: UnusualPattern[];
  missingExpectedAttributes: string[];

  // Performance optimization data
  parallelDetectionResults: ParallelDetectionResults;
  attributeComputationGraph: AttributeComputationNode[];
}

export interface AttributeCorrelation {
  attributes: string[];
  correlationType: 'positive' | 'negative' | 'conditional';
  strength: number;
  context: string;
  observedFrequency: number;
}

export interface UnusualPattern {
  description: string;
  involvedAttributes: string[];
  unusualness: number; // How different from typical patterns
  potentialCause: string;
  requiresInvestigation: boolean;
}

export interface ParallelDetectionResults {
  totalDetectionTimeMs: number;
  parallelDetectionsCount: number;
  sequentialDetectionsCount: number;
  parallelEfficiency: number;
  bottleneckAttributes: string[];
  optimizationOpportunities: string[];
}

export interface AttributeComputationNode {
  attribute: string;
  dependencies: string[];
  computationOrder: number;
  canRunInParallel: boolean;
  computationTimeMs: number;
  memoryRequirementMB: number;
}

/**
 * Attribute detection schemas matching the sophisticated patterns
 */
export interface AttributeDetectionSchemas {
  urgency: {
    high: UrgencyPattern[];
    medium: UrgencyPattern[];
    low: UrgencyPattern[];
  };
  domains: {
    extractionRules: DomainExtractionRule[];
    resolutionMode: 'runtimeResolved' | 'static';
    sourceGroups: Record<string, string[]>;
  };
  structuralPatterns: {
    emailFormat: StructuralPattern[];
    contentStructure: StructuralPattern[];
    metadata: StructuralPattern[];
  };
  temporalSignals: {
    schedulePatterns: TemporalPattern[];
    urgencyIndicators: TemporalPattern[];
    sequenceDetection: TemporalPattern[];
  };
}

export interface UrgencyPattern {
  field: string;
  operation: string;
  values: string[];
  weight: number;
  reasoning: string;
}

export interface DomainExtractionRule {
  sourceField: string;
  extractionMethod: 'fromHeader' | 'fromBody' | 'fromReplyTo' | 'fromLinkAnalysis';
  domainNormalization: boolean;
  subdomainHandling: 'include' | 'exclude' | 'separate';
}

export interface StructuralPattern {
  patternName: string;
  detectionMethod: string;
  matchCriteria: string[];
  confidence: number;
  contextRequirements: string[];
}

export interface TemporalPattern {
  patternType: string;
  timeFields: string[];
  analysisWindow: string;
  thresholds: Record<string, number>;
  seasonalAdjustment: boolean;
}

